/** @file*/

#include "internal_nn_math.h"
#include "riscv_nn_types.h"
#include "riscv_nn_basic.h"
#include "riscv_nn_support.h"

int32_t nn_lstm_step_s8(const int8_t *data_in,
                        const int8_t *hidden_in,
                        int8_t *hidden_out,
                        const riscv_nn_lstm_params2 *params,
                        riscv_nn_lstm_context2 *buffers,
                        const int32_t batch_offset)
{
    int16_t *forget_gate = buffers->temp1;
    int16_t *input_gate = buffers->temp1;
    int16_t *cell_gate = buffers->temp2;
    int16_t *output_gate = buffers->temp1;
    int16_t *hidden_temp = buffers->temp2;
    int16_t *cell_state = buffers->cell_state;

    nn_lstm_calculate_gate_s8_s16(data_in, hidden_in, &params->forget_gate, params, forget_gate, batch_offset);

    // Calculate first term of cell state in place early to maximise reuse of scratch-buffers
    riscv_nn_ew_mul_s16_asym(forget_gate,
                             cell_state,
                             0,
                             0,
                             cell_state,
                             0,
                             params->forget_to_cell_multiplier,
                             params->forget_to_cell_shift,
                             Q15_MIN,
                             Q15_MAX,
                             params->hidden_size * params->batch_size);

    nn_lstm_calculate_gate_s8_s16(data_in, hidden_in, &params->input_gate, params, input_gate, batch_offset);
    nn_lstm_calculate_gate_s8_s16(data_in, hidden_in, &params->cell_gate, params, cell_gate, batch_offset);

    // Reminder of cell state calculation, multiply and add to previous result.
    nn_elementwise_mul_acc_s16(forget_gate,
                               cell_gate,
                               0,
                               0,
                               cell_state,
                               0,
                               params->input_to_cell_multiplier,
                               params->input_to_cell_shift,
                               -params->cell_clip,
                               params->cell_clip,
                               params->hidden_size * params->batch_size);

    nn_lstm_calculate_gate_s8_s16(data_in, hidden_in, &params->output_gate, params, output_gate, batch_offset);

    // Calculate hidden state directly to output.
    riscv_nn_activate_s16_hp(cell_state, hidden_temp, params->hidden_size * params->batch_size, params->cell_scale_power + 12, NN_TANH);
    nn_elementwise_mul_s16_s8(output_gate,
                              hidden_temp,
                              hidden_out,
                              params->output_offset,
                              params->output_multiplier,
                              params->output_shift,
                              params->hidden_size,
                              params->batch_size,
                              batch_offset);

    return 0;
}

