#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
    int16_t   i_out_y, i_out_x, i_ker_y, i_ker_x;

    /*
     *  Use im2col with 4-column batching and nn_mat_mul_kernel_u8_bias_2sft_unroll4
     *  which implements a 4x4 tiled GEMM with vd4dotsu, vectorizing across the
     *  reduction dimension K (=in_tensor_ch * ker_dim_x * ker_dim_y). This achieves
     *  full vector utilization even when out_tensor_ch is small.
     */

    u8_t     *pBuffer = (u8_t*)in_tmp_buf;
    u8_t     *pOut = out_tensor;
    int bound_x_begin = (pad_x + stride_x - 1) / stride_x;
    int bound_x_end   = (in_tensor_dim_x + pad_x - ker_dim_x + stride_x) / stride_x;
    int bound_y_begin = (pad_y + stride_y - 1) / stride_y;
    int bound_y_end   = (in_tensor_dim_y + pad_y - ker_dim_y + stride_y) / stride_y;

    /* top part */
    for (i_out_y = 0; i_out_y < bound_y_begin; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
                                                      (u8_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    /* middle part -- split x into left, mid, right */
    for (; i_out_y < bound_y_end; i_out_y++)
    {
        /* left part */
        for (i_out_x = 0; i_out_x < bound_x_begin; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
                        i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
                                                      (u8_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }

        /* mid part -- no padding, use bulk copy */
        for (; i_out_x < bound_x_end; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                nn_dup_u8
                ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_out_x * stride_x - pad_x) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim_x);
                pBuffer += in_tensor_ch * ker_dim_x;
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
                                                      (u8_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }

        /* right part */
        for (; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
                        i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
                                                      (u8_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    /* bottom part */
    for (; i_out_y < out_tensor_dim_y; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
                        i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8
                        ((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
                                                      (u8_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (u8_t *)in_tmp_buf;
            }
        }
    }

    /* check if there are left-over pixels in the buffer (1..3 pixels) */
    if (pBuffer != (u8_t *)in_tmp_buf)
    {
        int leftover_bytes = pBuffer - (u8_t *)in_tmp_buf;
        int col_size = in_tensor_ch * ker_dim_x * ker_dim_y;

        /* drain 2 pixels if we have 2 or 3 left over */
        if (leftover_bytes >= 2 * col_size)
        {
            pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
                                                  (u8_t*)in_tmp_buf,
                                                  out_tensor_ch,
                                                  col_size,
                                                  pre_rshift,
                                                  out_scale,
                                                  post_rshift,
                                                  bias,
                                                  pOut);
            leftover_bytes -= 2 * col_size;
        }

        /* handle 1 remaining pixel with scalar path */
        if (leftover_bytes > 0)
        {
            const q7_t *pA = ker_weight;
            u8_t *pB = pBuffer - col_size;
            int i;

            for (i = 0; i < out_tensor_ch; i++)
            {
                q31_t sum = bias[i];
                uint16_t colCnt = col_size;
                u8_t *pB_iter = pB;

                while (colCnt)
                {
                    sum += *pA++ * *pB_iter++;
                    colCnt--;
                }

                sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                *pOut++ = NDS_ISA_SAT((sum >> post_rshift), 8);
            }
        }
    }

