                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }

        /* mid part -- no padding, use bulk copy */
        for (; i_out_x < bound_x_end; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                nn_dup_s8
                ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_out_x * stride_x - pad_x) * in_tensor_ch, pBuffer, in_tensor_ch * ker_dim_x);
                pBuffer += in_tensor_ch * ker_dim_x;
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,
                                                      (q7_t*)in_tmp_buf,
