                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,
                                                      (q7_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* bottom part */
    for (; i_out_y < out_tensor_dim_y; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x;
                        i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_s8
                        ((q7_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (q7_t *)in_tmp_buf + 4 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_q7_bias_2sft_unroll4(ker_weight,
                                                      (q7_t*)in_tmp_buf,
                                                      out_tensor_ch,
                                                      in_tensor_ch * ker_dim_x * ker_dim_y,
                                                      pre_rshift,
                                                      out_scale,
                                                      post_rshift,
                                                      bias,
                                                      pOut);
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* check if there are left-over pixels in the buffer (1..3 pixels) */
    if (pBuffer != (q7_t *)in_tmp_buf)
    {
        int leftover_bytes = pBuffer - (q7_t *)in_tmp_buf;
        int col_size = in_tensor_ch * ker_dim_x * ker_dim_y;

        /* drain 2 pixels if we have 2 or 3 left over */
        if (leftover_bytes >= 2 * col_size)
        {
            pOut = nn_mat_mul_kernel_q7_bias_2sft(ker_weight,
                                                  (q7_t*)in_tmp_buf,
                                                  out_tensor_ch,
                                                  col_size,
                                                  pre_rshift,
                                                  out_scale,
                                                  post_rshift,
                                                  bias,
                                                  pOut);
            leftover_bytes -= 2 * col_size;
        }

        /* handle 1 remaining pixel with scalar path */
        if (leftover_bytes > 0)
        {
            const q7_t *pA = ker_weight;
            q7_t *pB = pBuffer - col_size;
            int i;

            for (i = 0; i < out_tensor_ch; i++)
            {
                q31_t sum = bias[i];
                uint16_t colCnt = col_size;
                q7_t *pB_iter = pB;

                while (colCnt)
                {
                    sum += *pA++ * *pB_iter++;
                    colCnt--;
                }

                sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 8);
            }
        }
    }

