            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);

            //add bias back
            vl = __riscv_vsetvl_e32m1(1);
            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
