                    i_ker_y++)
            {
                nn_dup_u8((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_out_x * stride_x - pad_x) * in_tensor_ch,
                              pBuffer, in_tensor_ch * ker_dim_x);
                pBuffer += in_tensor_ch * ker_dim_x;
            }

            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_u8_q7_bias_2sft(ker_weight,
                        (u8_t*)in_tmp_buf,
                        out_tensor_ch,
                        in_tensor_ch * ker_dim_x * ker_dim_y,
                        pre_rshift,
                        out_scale,
                        post_rshift,
                        bias,
                        pOut);
                /* counter reset */
                pBuffer = (u8_t*)in_tmp_buf;
            }
        }

        /* right part */
        for (; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y;
                    i_ker_y++)
            {
