                        i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        nn_set_zero_u8(pBuffer, sizeof(u8_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
                                      pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u8_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut = nn_mat_mul_kernel_u8_q7_bias_2sft(ker_weight,
                        (u8_t*)in_tmp_buf,
                        out_tensor_ch,
                        in_tensor_ch * ker_dim_x * ker_dim_y,
                        pre_rshift,
                        out_scale,
                        post_rshift,
                        bias,
                        pOut);
