        vl = __riscv_vsetvl_e32m1(1);
        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0, vl);     //const zero for redsum

        for (i = 0; i < out_tensor_ch; i++)
        {
            u8_t      *p_in = (u8_t*)in_tmp_buf;
            uint16_t colCnt2 = colCnt;

            //clear v0~v7
            vl = __riscv_vsetvl_e32m8(colCnt);
            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);

            while (colCnt2 > 0)
            {
                vl = __riscv_vsetvl_e8m8(colCnt2);
                //load src1
                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
                //load src2
                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
                //bump pointers and update loop counter
                colCnt2 -= vl;
                p_wt += vl;
                p_in += vl;
                //set the proper avl/SEW/LMUL values for vd4dot
                vl >>= 2;
                vl = __riscv_vsetvl_e32m8(vl);
                //acc += src1 * src2
                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_u8m8, vl);
            }

            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);

            //add bias back
            vl = __riscv_vsetvl_e32m1(1);
            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
            vSum = __riscv_vadd(vSum, vBias, vl);

