                    else
                    {
                        nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
                                                    pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut =
                    nn_mat_mul_kernel_q7_u16_q7_reordered_bias_2sft(ker_weight,
                                                                    (u16_t*)in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim_x * ker_dim_y,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = (u16_t*)in_tmp_buf;
            }
        }

        /* mid part */
        for (; i_out_x < out_tensor_dim_x - pad_x; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
            {
                nn_dup_u8_u16_reordered((u8_t *) in_tensor +
                                            (i_ker_y * in_tensor_dim_x + i_out_x * stride_x - pad_x) * in_tensor_ch,
                                            pBuffer, in_tensor_ch * ker_dim_x);
                pBuffer += in_tensor_ch * ker_dim_x;
            }

            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut =
                    nn_mat_mul_kernel_q7_u16_q7_reordered_bias_2sft(ker_weight,
                                                                    (u16_t*)in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim_x * ker_dim_y,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = (u16_t*)in_tmp_buf;
            }
        }

        /* right part */
        for (; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
                {
                    if (i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
                                                    pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut =
                    nn_mat_mul_kernel_q7_u16_q7_reordered_bias_2sft(ker_weight,
                                                                    (u16_t*)in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim_x * ker_dim_y,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = (u16_t*)in_tmp_buf;
            }
        }
    }

    for (; i_out_y < out_tensor_dim_y; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            /* This part implements the im2col function */
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        memset(pBuffer, 0, sizeof(q15_t)*in_tensor_ch);
                    }
                    else
                    {
                        nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch,
                                                    pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }

            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
            {
                pOut =
                    nn_mat_mul_kernel_q7_u16_q7_reordered_bias_2sft(ker_weight,
                                                                    (u16_t*)in_tmp_buf,
                                                                    out_tensor_ch,
                                                                    in_tensor_ch * ker_dim_x * ker_dim_y,
                                                                    pre_rshift,
                                                                    out_scale,
                                                                    post_rshift,
                                                                    bias,
                                                                    pOut);
                /* counter reset */
                pBuffer = (u16_t*)in_tmp_buf;
            }
        }
    }

    /* check if there is left-over for compute */
    if (pBuffer != (u16_t*)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int       i;
        for (i = 0; i < out_tensor_ch; i++)
        {
            q31_t     sum = bias[i];
            u16_t    *pB = (u16_t*)in_tmp_buf;

            /* basically each time it process 4 entries */
            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
            while (colCnt)
            {
                q31_t     inA1, inA2;
                q31_t     inB1, inB2;

                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
                inB1 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA1, inB1);
                inB2 = *__SIMD32(pB)++;
                sum = NDS_DSP_KMADA(sum, inA2, inB2);
                colCnt--;
            }

            //since in_tensor_ch is multiple of 4 (input constraints), the
            //following codes will not be reached
            // colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x3;
            // while (colCnt)
            // {
            //     q7_t      inA1 = *pA++;
            //     u16_t     inB1 = *pB++;
            //     sum += inA1 * inB1;
            //     colCnt--;
            // }

            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_DSP_SATS((sum >> post_rshift), 8);
        }
    }
#else
    int       i, j, k, l, m, n;
    int       conv_out;
    int       in_row, in_col;

    for (i = 0; i < out_tensor_ch; i++)
    {
        for (j = 0; j < out_tensor_dim_y; j++)
        {
            for (k = 0; k < out_tensor_dim_x; k++)
            {
                conv_out = bias[i];
                for (m = 0; m < ker_dim_y; m++)
                {
                    for (n = 0; n < ker_dim_x; n++)
                    {
                        /* if-for implementation */
                        in_row = stride_y * j + m - pad_y;
                        in_col = stride_x * k + n - pad_x;
                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
                        {
                            for (l = 0; l < in_tensor_ch; l++)
                            {
                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_x + n) * in_tensor_ch + l];
                            }
                        }
                    }
                }
                conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
                out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SATS((conv_out >> post_rshift), 8);
            }
        }
    }
#endif
#endif  //ENA_EMPTY_FUN

    /* Return to application */
    return 0;
}

