#if defined(ENA_VEC_ISA) && defined(ENA_TILING)
    /* cache is 512KB, type is q7 */
    uint32_t tiling_size = 256;
    /* num of columnar */
    int col_counter = 0;
    int16_t    i_out_y, i_out_x, i_ker_y, i_ker_x;
    unsigned long addr_in_tmp_buf;

    /*
     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
     *  im2col are done to output in q15_t format from q7_t input
     */
    const long align_byte = 64;
    q7_t *pBuffer = (q7_t*)in_tmp_buf;
    q15_t *pOut = out_tensor;
    q31_t *dst_q31;

    q7_t *src2 = (q7_t *)in_tmp_buf
                         + sizeof(*in_tensor) * tiling_size * in_tensor_ch * ker_dim_x * ker_dim_y; //matrix_A's memory space
    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);  // align the starting addresss
    addr_in_tmp_buf = (unsigned long)src2;
    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch * ker_dim_x * ker_dim_y;
    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
    dst_q31 = (q31_t *)addr_in_tmp_buf;

    /* transpose the kernel_weight for matrix multiplication */
    const long row = out_tensor_ch;
    const long col = ker_dim_x * ker_dim_y * in_tensor_ch;
    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);

    /* This part implements the im256col function */
    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
    {
        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
        {
            for (i_ker_y = i_out_y * stride_y - pad_y; i_ker_y < i_out_y * stride_y - pad_y + ker_dim_y; i_ker_y++)
            {
                for (i_ker_x = i_out_x * stride_x - pad_x; i_ker_x < i_out_x * stride_x - pad_x + ker_dim_x; i_ker_x++)
                {
                    if (i_ker_y < 0 || i_ker_y >= in_tensor_dim_y || i_ker_x < 0 || i_ker_x >= in_tensor_dim_x)
                    {
                        /* Filling 0 for out-of-bound paddings */
                        nn_set_zero_s8(pBuffer, sizeof(q7_t)*in_tensor_ch);
                    }
                    else
                    {
                        /* Copying the pixel data to column */
                        nn_dup_s8((q7_t *)in_tensor + (i_ker_y * in_tensor_dim_x + i_ker_x) * in_tensor_ch, pBuffer, in_tensor_ch);
                    }
                    pBuffer += in_tensor_ch;
                }
            }
            col_counter++;

            /* Computation is filed for [tiling_size] columns */
            if (col_counter == tiling_size)
            {
                pOut = nn_mat_mul_kernel_tiling_bias_s8_s16_s8((q7_t *)in_tmp_buf,
                                                                src2,
                                                                dst_q31,
                                                                pOut,
                                                                col_counter,
                                                                in_tensor_ch * ker_dim_x * ker_dim_y,
                                                                out_tensor_ch,
                                                                pre_rshift,
                                                                out_scale,
                                                                post_rshift,
                                                                bias,
                                                                tiling_size);
                /* reset */
                col_counter = 0;
                pBuffer = (q7_t *)in_tmp_buf;
            }
        }
    }

    /* check if there is left-over for compute */
    pOut = nn_mat_mul_kernel_tiling_bias_s8_s16_s8((q7_t*)in_tmp_buf,
                                                   src2,
                                                   dst_q31,
                                                   pOut,
                                                   col_counter,
                                                   in_tensor_ch * ker_dim_x * ker_dim_y,
                                                   out_tensor_ch,
                                                   pre_rshift,
                                                   out_scale,
                                                   post_rshift,
                                                   bias,
                                                   tiling_size);

