                colCnt2 -= vl;
                pA += vl;
                pB += vl;
            }

            NDS_VEC_VSETVLI_E32_M2(vl, colCnt);     //note the avl here
            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V2, NDS_VEC_V0);
            //move vr results to gpr
            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);

            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 16);
        }
    }
