#elif defined(ENA_DSP_ISA_64)
    if (pBuffer != (q7_t*)in_tmp_buf)
    {
        const q7_t *pA = ker_weight;
        int       i;
        for (i = 0; i < out_tensor_ch; i++)
        {
            long   sum = 0;
            q7_t    *pB = (q7_t*)in_tmp_buf;

            /* basically each time it process 8 entries */
            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 3;

            while (colCnt)
            {
                long inA1, inB1;

                inA1 = *__SIMD64(pA)++;
                inB1 = *__SIMD64(pB)++;
                sum  = NDS_DSP_SMAQA(sum, inA1, inB1);
                colCnt--;
            }
            //sum up the high and low part results (SIMD results)
            sum  = (q31_t)(sum >> 32) + (q31_t)sum;

            colCnt = (in_tensor_ch * ker_dim_y * ker_dim_x) & 0x7;
            while (colCnt)
            {
                q7_t      inA1 = *pA++;
                q7_t      inB1 = *pB++;
                sum += inA1 * inB1;
                colCnt--;
            }

             /* add bias back in to sum */
            sum += bias[i];

            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
            *pOut = NDS_DSP_SATS(((q31_t)sum >> post_rshift), 16);
            pOut++;
        }
    }
#else
    if (pBuffer != (q7_t *)in_tmp_buf)
